INSERT INTO characters (deck, gender, id, name, teams, volume_credits, origin) VALUES ('Garth Ranzz is one of the three original members/founders of the Legion of Super-Heroes. Empowered with the ability to control electricity, he is called Lightning Lad. Garth is the older twin brother of fellow Legionnaire Lightning Lass, and the younger brother of Lightning Lord.', '1', '1253', 'Lightning Lad', '[{"id": 19241}, {"id": 56923}, {"id": 61879}, {"id": 61477}, {"id": 66481}, {"id": 47189}]', '[{"id": 43262}]', NULL);
INSERT INTO characters (deck, gender, id, name, teams, volume_credits, origin) VALUES ('Nura Nal is from the planet Naltor, where all of the inhabitants have the ability to see into the future, though Nura''s precognitive ability is the strongest of her race. As Dream Girl, she is a longtime member of the Legion of Super-Heroes.', '2', '1254', 'Dream Girl', '[{"id": 59156}, {"id": 47111}, {"id": 19241}, {"id": 56923}, {"id": 64515}, {"id": 40395}]', '[{"id": 118203}]', NULL);
INSERT INTO characters (deck, gender, id, name, teams, volume_credits, origin) VALUES ('Brainiac 5 is a long-standing member of the Legion of Super-Heroes with a 12th level intelligence and force-field belt. He is an expert on the science of time-travel (and many other things).', '1', '1255', 'Brainiac 5', '[{"id": 58973}, {"id": 55891}, {"id": 47222}, {"id": 19241}, {"id": 56923}, {"id": 40395}]', '[{"id": 43262}]', NULL);
INSERT INTO characters (deck, gender, id, name, teams, volume_credits, origin) VALUES ('He is a member of the Legion of Super-Heroes, a super group based in the 30th and 31st centuries of the DC Universe. He''s a genius in biochemistry and designed a serum to give him the ability to turn invisible.', '1', '1256', 'Invisible Kid', '[{"id": 61727}, {"id": 19241}, {"id": 56923}]', '[{"id": 45772}]', NULL);
INSERT INTO characters (deck, gender, id, name, teams, volume_credits, origin) VALUES ('Tinya Wazzo is a native of the extra-dimensional planet Bgztl, giving her the power to phase through solid objects. She is the only member of her race with the ability to pass through the Phantom Zone and onto Earth. She is a long-time member of the Legion of Super-Heroes under the code name Phantom Girl.', '2', '1257', 'Phantom Girl', '[{"id": 63585}, {"id": 61727}, {"id": 19241}, {"id": 56923}]', '[{"id": 45660}]', NULL);
INSERT INTO characters (deck, gender, id, name, teams, volume_credits, origin) VALUES ('A member of the Legion of Super-Heroes, who taps into solar energy to produce whatever degree of flame or luminance he wishes.', '1', '1259', 'Sun Boy', '[{"id": 50743}, {"id": 52207}, {"id": 19241}, {"id": 56923}, {"id": 47457}]', '[{"id": 45776}]', NULL);
INSERT INTO characters (deck, gender, id, name, teams, volume_credits, origin) VALUES ('Member of the Legion of Super-Heroes able to induce mass and gravity. Former member of the Justice Society of America.', '1', '1260', 'Thom Kallor', '[{"id": 31815}, {"id": 45101}, {"id": 27589}, {"id": 61727}, {"id": 47111}, {"id": 19241}, {"id": 56923}, {"id": 61336}, {"id": 47187}, {"id": 47418}]', '[{"id": 118203}]', NULL);
INSERT INTO characters (deck, gender, id, name, teams, volume_credits, origin) VALUES ('Tasmia Mallor is the champion of her homeworld of Talok VIII and has the power to project and control darkness. As Shadow Lass, she is a long-time member of the Legion of Super-Heroes.', '2', '1261', 'Shadow Lass', '[{"id": 61727}, {"id": 19241}, {"id": 58774}]', '[{"id": 118617}]', NULL);
INSERT INTO characters (deck, gender, id, name, teams, volume_credits, origin) VALUES ('Luornu Durgo is a native of Cargg, a planet with three suns, which gives her the ability to split into three identical bodies. As Triplicate Girl, she became one of the first members of the Legion of Super-Heroes. Luornu recently gained the ability to split into a virtually endless number of bodies and now calls herself Duplicate Girl.', '2', '1262', 'Duplicate Girl', '[{"id": 64517}, {"id": 47210}, {"id": 61727}, {"id": 47111}, {"id": 19241}, {"id": 56923}]', '[{"id": 45660}]', NULL);
INSERT INTO characters (deck, gender, id, name, teams, volume_credits, origin) VALUES ('Able to transmute elements by touch, Element Lad is the last survivor of his race and a member of the Legion of Super-Heroes.', '1', '1263', 'Element Lad', '[{"id": 50743}, {"id": 61727}, {"id": 19241}, {"id": 56923}, {"id": 51925}]', '[{"id": 118617}]', NULL);
