INSERT INTO characters (deck, gender, id, name, teams, volume_credits, origin) VALUES ('Ultra Boy is a former leader and current member of the Legion of Super-Heroes. He possesses most of Superboy''s powers, but can only use them one at a time. His Penetra-Vision allows him to see through lead (unlike Superboy''s X-ray vision), and his invulnerability is more adaptable than that of Superboy or Mon-El.', '1', '1267', 'Ultra Boy', '[{"id": 19241}, {"id": 56923}, {"id": 47418}, {"id": 47189}]', '[{"id": 118617}]', NULL);
